from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismCreatePlayblastNode(BaseNode):
    name = "Prism: Create Playblast"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("task", "string", widget_type="text", default="preview")
        self.add_input("comment", "string", widget_type="text", default="")
        self.add_input("start_frame", "int", widget_type="int", default=1)
        self.add_input("end_frame", "int", widget_type="int", default=100)
        self.add_output("success", "bool")
        self.add_output("output_path", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        task = inputs.get('task') or 'preview'
        comment = inputs.get('comment') or ''
        s = int(inputs.get('start_frame') or 1)
        e = int(inputs.get('end_frame') or 100)
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'success': False, 'output_path': ''}
        try:
            res = None
            kwargs = {'task': task, 'comment': comment, 'startFrame': s, 'endFrame': e}
            for owner in (getattr(core, 'mediaProducts', None), getattr(core, 'media', None), getattr(core, 'appPlugin', None)):
                if owner is None: continue
                fn = getattr(owner, 'createPlayblast', None)
                if fn is None: continue
                try:
                    res = fn(**kwargs)
                except TypeError:
                    res = fn(task, comment)
                break
            if res is None:
                self.log_error("No createPlayblast method found.")
                return {'success': False, 'output_path': ''}
            path = ''
            if isinstance(res, dict): path = res.get('path') or res.get('outputPath') or ''
            else: path = str(res or '')
            self.log_success(f"Playblast created: {path or '(ok)'}")
            await self.set_output('exec_out', True)
            return {'success': True, 'output_path': path}
        except Exception as e:
            self.log_error(f"createPlayblast failed: {e}")
            return {'success': False, 'output_path': ''}

def register_node():
    return PrismCreatePlayblastNode
